let filteredInvestors = [...investorsData];
let searchQuery = "";

// 페이지 로드 시 투자자 카드 렌더링
document.addEventListener("DOMContentLoaded", () => {
  renderInvestors(investorsData);
  updateResultsCount(investorsData.length);

  // URL ?id= 파라미터로 진입 시 해당 투자자 모달 자동 오픈
  const params = new URLSearchParams(window.location.search);
  const targetId = parseInt(params.get("id"));
  if (targetId) {
    openInvestorModal(targetId);
  }

  // URL ?filter= 파라미터로 진입 시 해당 특수 필터 자동 활성화
  const filterParam = params.get("filter");
  if (filterParam && ["tps", "sups", "lips", "tops"].includes(filterParam)) {
    toggleSpecialFilter(filterParam);
  }
});

// 검색 기능
function handleSearch() {
  const input = document.getElementById("investorSearch");
  const clearBtn = document.getElementById("searchClear");
  const searchStats = document.getElementById("searchStats");
  const searchKeyword = document.getElementById("searchKeyword");

  searchQuery = input.value.trim();

  // Clear 버튼 표시/숨김
  if (searchQuery.length > 0) {
    clearBtn.classList.add("visible");
    searchStats.style.display = "flex";
    searchKeyword.textContent = searchQuery;
  } else {
    clearBtn.classList.remove("visible");
    searchStats.style.display = "none";
  }

  applyFilters();
}

// 검색 초기화
function clearSearch() {
  const input = document.getElementById("investorSearch");
  const clearBtn = document.getElementById("searchClear");
  const searchStats = document.getElementById("searchStats");

  input.value = "";
  searchQuery = "";
  clearBtn.classList.remove("visible");
  searchStats.style.display = "none";

  applyFilters();
}

// 투자자 카드 렌더링
